// 0.8.0 / 0.8.1 — illustrative; the bug is structural, not input-driven.
// Any panic while holding the guard poisons the lock; the std-RwLock
// type below stands in for `AccessPointTable::inner` in those versions.
use std::sync::{Arc, RwLock};
use std::thread;

struct PanickyDrop;
impl Drop for PanickyDrop {
    fn drop(&mut self) { panic!("drop in guard scope"); }
}

let table: Arc<RwLock<Vec<PanickyDrop>>> = Arc::new(RwLock::new(vec![PanickyDrop]));

// Thread T1: holds the write guard, triggers an in-guard panic via Drop.
let t = {
    let table = table.clone();
    thread::spawn(move || {
        let mut g = table.write().unwrap();
        g.clear(); // PanickyDrop::drop panics while we hold the guard
    })
};
let _ = t.join();

// Thread T2: every subsequent access panics on .unwrap() — lock is poisoned.
// In 0.8.0/0.8.1 this is exactly what `AccessPointTable::get`, `insert`,
// `refresh_path`, etc. do on every request after the first in-guard panic.
let _ = table.read().unwrap(); // panics: PoisonError
